List customers from USA who have completed orders

Schema:
CREATE TABLE customers (customer_id INTEGER PRIMARY KEY, name TEXT, email TEXT, country TEXT, created_at TEXT);
CREATE TABLE orders (order_id INTEGER PRIMARY KEY, customer_id INTEGER, order_date TEXT, total_amount REAL, status TEXT);
CREATE TABLE order_items (item_id INTEGER PRIMARY KEY, order_id INTEGER, product_id INTEGER, quantity INTEGER, price REAL);
CREATE TABLE products (product_id INTEGER PRIMARY KEY, name TEXT, category TEXT, price REAL, stock INTEGER);

WITH usa_customers AS (
  SELECT customer_id FROM customers WHERE country = 'USA'
),
completed_orders AS (
  SELECT DISTINCT customer_id FROM orders WHERE status = 'completed'
)
SELECT c.* FROM customers c WHERE c.customer_id IN (SELECT customer_id FROM usa_customers) AND c.customer_id IN (SELECT customer_id FROM completed_orders);

Show Engineering employees with assignments under 80 hours

Schema:
CREATE TABLE employees (emp_id INTEGER PRIMARY KEY, name TEXT, department TEXT, salary REAL, hire_date TEXT, manager_id INTEGER);
CREATE TABLE departments (dept_id INTEGER PRIMARY KEY, name TEXT, budget REAL, location TEXT);
CREATE TABLE projects (proj_id INTEGER PRIMARY KEY, name TEXT, dept_id INTEGER, start_date TEXT, end_date TEXT);
CREATE TABLE assignments (emp_id INTEGER, proj_id INTEGER, role TEXT, hours INTEGER);

WITH eng_emps AS (
  SELECT emp_id FROM employees WHERE department = 'Engineering'
),
light_work AS (
  SELECT DISTINCT emp_id FROM assignments WHERE hours < 80
)
SELECT e.* FROM employees e WHERE e.emp_id IN (SELECT emp_id FROM eng_emps) AND e.emp_id IN (SELECT emp_id FROM light_work);

Find the maximum GPA per major

Schema:
CREATE TABLE students (student_id INTEGER PRIMARY KEY, name TEXT, major TEXT, gpa REAL, year INTEGER);
