WITH older_patients AS (
  SELECT patient_id FROM patients WHERE dob < '1980-01-01'
),
aspirin_patients AS (
  SELECT DISTINCT a.patient_id FROM appointments a JOIN prescriptions pr ON a.appt_id = pr.appt_id WHERE pr.medication = 'Aspirin'
)
SELECT p.* FROM patients p WHERE p.patient_id IN (SELECT patient_id FROM older_patients) AND p.patient_id IN (SELECT patient_id FROM aspirin_patients);

