CREATE TABLE students (student_id INTEGER PRIMARY KEY, name TEXT, major TEXT, gpa REAL, year INTEGER);
CREATE TABLE courses (course_id TEXT PRIMARY KEY, title TEXT, department TEXT, credits INTEGER);
CREATE TABLE enrollments (student_id INTEGER, course_id TEXT, semester TEXT, grade TEXT);
CREATE TABLE professors (prof_id INTEGER PRIMARY KEY, name TEXT, department TEXT);

WITH three_credit AS (
  SELECT course_id FROM courses WHERE credits = 3
),
cs_courses AS (
  SELECT course_id FROM courses WHERE department = 'Computer Science'
)
SELECT c.* FROM courses c WHERE c.course_id IN (SELECT course_id FROM three_credit) AND c.course_id IN (SELECT course_id FROM cs_courses);

